import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.ruleset.standard.StandardRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode

class DebugTokensRule : StandardRule("debug-tokens") {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        // Print all token types to see what the range until operator uses
        if (node.text.contains("..<")) {
            println("Token: ${node.elementType}, Text: '${node.text}'")
            node.getChildren(null).forEach { child ->
                println("  Child Token: ${child.elementType}, Text: '${child.text}'")
                child.getChildren(null).forEach { grandchild ->
                    println("    Grandchild Token: ${grandchild.elementType}, Text: '${grandchild.text}'")
                }
            }
        }
    }
}"}

